#include <stdio.h>
#include <string.h>

int isPalindrome(const char *s) {
    int i = 0, j = strlen(s) - 1;
    while (i < j) {
        if (s[i] != s[j]) return 0;
        ++i; --j;
    }
    return 1;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[105];
    while (T--) {
        scanf("%s", s);
        printf(isPalindrome(s) ? "YES\n" : "NO\n");
    }
    return 0;
}

