#!/usr/bin/env python3
import sys

def is_palindrome(s: str) -> bool:
    i, j = 0, len(s) - 1
    while i < j:
        if s[i] != s[j]:
            return False
        i += 1
        j -= 1
    return True

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        s = data[i]
        out.append('YES' if is_palindrome(s) else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

